import java.util.Scanner;

public class SecureBufferImplementation {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine().trim(); // Read a full line of input and trim leading/trailing spaces

        int bufferSize = 10;
        char[] buffer = new char[bufferSize];

        if (input.length() > bufferSize) {
            System.out.println("Input exceeds buffer size. Please enter a string with maximum " + bufferSize + " characters.");
            return;
        }

        input.getChars(0, input.length(), buffer, 0);

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

